```ts
import * as cdk from 'aws-cdk-lib';
import * as s3 from 'aws-cdk-lib/aws-s3';
import * as iam from 'aws-cdk-lib/aws-iam';
import * as logs from 'aws-cdk-lib/aws-logs';
import * as s3deploy from 'aws-cdk-lib/aws-s3-deployment';

export class FinancialRecordsStack extends cdk.Stack {
  constructor(scope: cdk.Construct, id: string, props?: cdk.StackProps) {
    super(scope, id, props);

    // Create an S3 bucket for customer financial records
    const financialRecordsBucket = new s3.Bucket(this, 'FinancialRecordsBucket', {
      bucketName: 'financial-records-bucket',
      removalPolicy: cdk.RemovalPolicy.RETAIN, // Retain bucket on deletion
      encryption: s3.BucketEncryption.KMS_MANAGED, // Use AWS KMS for encryption
      versioned: true, // Enable versioning
      blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL, // Block public access
      lifecycleRules: [
        {
          expiration: cdk.Duration.days(365), // Expire after 1 year
          transitions: [
            {
              storageClass: s3.StorageClass.INFREQUENT_ACCESS,
              transitionAfter: cdk.Duration.days(30)
            },
            {
              storageClass: s3.StorageClass.GLACIER,
              transitionAfter: cdk.Duration.days(90)
            }
          ],
          id: 'FinancialRecordsLifecycle'
        }
      ],
      loggingConfiguration: {
        logFilePrefix: 'access-logs/',
        destinationBucket: new s3.Bucket(this, 'AccessLogsBucket', {
          blockPublicAccess: s3.BlockPublicAccess.BLOCK_ALL,
          removalPolicy: cdk.RemovalPolicy.RETAIN
        })
      }
    });

    // Add a policy to allow access to the bucket (e.g., from an application)
    const accessPolicy = new iam.PolicyStatement({
      actions: ['s3:GetObject', 's3:PutObject'],
      resources: [financialRecordsBucket.arnForObjects('*')],
      principals: [new iam.AccountRootPrincipal()]
    });

